queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:building_type_id ?cg . ?child a :Building_Types ; p:id ?cg . ?l p:architect_id ?pg . ?parent a :Architects ; p:id ?pg . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Architects } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?type WHERE {
  ?architects_building_types a :Architects_Building_Types .
  ?building_types a :Building_Types .
  ?architects_building_types p:hasBuilding_Types ?building_types .
  ?architects a :Architects .
  ?architects_building_types p:hasArchitects ?architects .
  ?architects p:name ?name .
  ?building_types p:type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:building_type_id ?cg . ?child a :Building_Types ; p:id ?cg . ?l p:architect_id ?pg . ?parent a :Architects ; p:id ?pg . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Architects } }
  FILTER(?nf = ?total)
} }
}
